function ids() { let value = 0; return () => String(++value); }
function interpreter() { return { async interpretPlayerInput(request) { return { schemaVersion: 1, requestId: request.requestId, correlationId: request.correlationId, serverCorrelationId: "server-1", result: { schemaVersion: 1, requestId: request.requestId, correlationId: request.correlationId, modelOutput: { schemaVersion: 1, alternatives: [{ alternativeId: "alternative-1", confidence: 1, speechActs: [{ type: "non_game_statement", sourceSpan: { start: 0, end: 5 } }] }] }, diagnostics: { providerName: "test", model: "test", attemptCount: 1, elapsedMs: 0 } } }; } }; }
function game(options = {}) { return WerewolfGame.create({ seed: 1, scenario: "sample", shuffleRoles: false, createId: ids(), interpreterValidationEnabled: true, playerConversationCommitEnabled: true, playerStructuredConsumerEnabled: true, interpreterProvider: interpreter(), responseProvider: { async generateResponse() { return { text: "response", providerName: "test", model: "test", usage: null, notes: [] }; } }, ...options }); }
async function action(instance = game()) { return { instance, result: await instance.dispatchPlayerAction({ type: "ask_npc", targetId: "npc1", input: "hello" }) }; }
function authoritative(instance) { return structuredClone({ stateVersion: instance.state.stateVersion, turnId: instance.state.turnId, turnOrder: instance.state.turnOrder, phase: instance.state.phase, conversation: instance.state.conversation, playerLog: instance.state.playerLog, players: instance.state.players }); }
function transitionIdentity(result) { return { modeTransitionId: result.modeTransitionId, gameSessionId: result.gameSessionId, consumerId: result.consumerId, sinkType: result.sinkType, proposedCutoverPublicationSlotOrder: result.proposedCutoverPublicationSlotOrder }; }
function fakeDom({ appendThrows = false, attach = true } = {}) { const document = { createElement() { return { className: "", dataset: {}, textContent: "", children: [], parentNode: null, append(...children) { this.children.push(...children); }, remove() { if (!this.parentNode) return; this.parentNode.children = this.parentNode.children.filter((node) => node !== this); this.parentNode = null; } }; } }; const container = { children: [], append(node) { if (appendThrows) throw new Error("append failed"); if (attach) { this.children.push(node); node.parentNode = this; } }, replaceChildren(...nodes) { for (const child of this.children) if (!nodes.includes(child)) child.parentNode = null; this.children = [...nodes]; for (const node of nodes) node.parentNode = this; }, querySelectorAll() { return this.children.filter((node) => node.dataset?.publicationId); } }; return { document, container }; }
async function consume(instance, result, sinkType = "cli", options = {}) { const visible = options.visible ?? [], bookkeeping = options.bookkeeping ?? new Map(), write = options.write ?? (async (entry) => { visible.push(entry); return entry; }); await consumeLiveActionDisplay({ game: instance, action: result, consumerId: `${sinkType}-main`, sinkType, bookkeeping, writeStructured: write, writeLegacy: write }); return { visible, bookkeeping }; }

test("delivery state machine requires sink success receipt and never mutates authoritative state", async () => {
  const { instance, result } = await action(), publicationId = result.deliveryPublicationIds[0], before = authoritative(instance), attempt = instance.preparePlayerPublicationDelivery({ publicationId, consumerId: "browser", sinkType: "browser" }); assert.equal(instance.playerPublicationDeliveryController.stateFor(publicationId), "prepared"); assert.deepEqual(authoritative(instance), before);
  assert.throws(() => instance.getPlayerPublicationSinkReceipt({ publicationId }), (error) => error.code === "invalid_sink_success_receipt"); const capability = instance.beginPlayerPublicationSink({ deliveryAttemptId: attempt.deliveryAttemptId }); assert.equal(instance.playerPublicationDeliveryController.stateFor(publicationId), "in_flight"); assert.throws(() => instance.acknowledgePlayerPublication({}), (error) => error.code === "invalid_sink_success_receipt");
  const receipt = instance.completePlayerPublicationSink(capability); assert.equal(instance.playerPublicationDeliveryController.stateFor(publicationId), "sink_succeeded"); const acknowledged = instance.acknowledgePlayerPublication(receipt); assert.equal(acknowledged.status, "acknowledged"); assert.equal(instance.playerPublicationDeliveryController.stateFor(publicationId), "acknowledged"); assert.deepEqual(authoritative(instance), before);
});

