function interpreterFor(acts) { return { async interpretPlayerInput(request) { return { schemaVersion: 1, requestId: request.requestId, correlationId: request.correlationId, serverCorrelationId: "server-1", result: { schemaVersion: 1, requestId: request.requestId, correlationId: request.correlationId, modelOutput: { schemaVersion: 1, alternatives: [{ alternativeId: "alternative-1", confidence: 1, speechActs: acts }] }, diagnostics: { providerName: "test", model: "test", attemptCount: 1, elapsedMs: 0 } } }; } }; }
function consumerGame(acts, consumer = true) { return WerewolfGame.create({ seed: 1, scenario: "sample", shuffleRoles: false, createId: consumerIds(), interpreterValidationEnabled: true, playerConversationCommitEnabled: true, playerStructuredConsumerEnabled: consumer, interpreterProvider: interpreterFor(acts), responseProvider: { async generateResponse() { return { text: "NPC response", providerName: "test", model: "test", usage: null, notes: [] }; } } }); }
function participants(instance) { return Object.fromEntries([["player", { participantId: "player", displayName: "Player" }], ...instance.state.players.map((player) => [player.id, { participantId: player.id, displayName: player.name }])]); }
async function committed(acts, raw = "hello") { const instance = consumerGame(acts, false); await instance.dispatchPlayerAction({ type: "ask_npc", targetId: "npc1", input: raw }); return instance; }
function renderPublication(instance, publicationId = instance.state.conversation.publications[0].publicationId) { return renderPlayerPublication({ gameSessionId: instance.state.gameSessionId, conversation: instance.state.conversation, legacyPlayerLog: instance.state.playerLog, publicationId, publicParticipantsById: participants(instance), resolveCompatibilityMapping: (id) => instance.getPlayerLegacyDisplayCompatibilityRecord({ publicationId: id }) }); }

