test("dangling, duplicate, and invalid publication graphs fail closed with typed consumer errors", async () => {
  const instance = await committed([{ type: "non_game_statement", sourceSpan: { start: 0, end: 5 } }]), publicationId = instance.state.conversation.publications[0].publicationId, common = { gameSessionId: instance.state.gameSessionId, legacyPlayerLog: instance.state.playerLog, publicationId, publicParticipantsById: participants(instance) }; const missingInput = structuredClone(instance.state.conversation); missingInput.inputRecords = []; assert.throws(() => renderPlayerPublication({ ...common, conversation: missingInput }), (error) => error.code === "dangling_input_reference"); const duplicate = structuredClone(instance.state.conversation); duplicate.publications.push(structuredClone(duplicate.publications[0])); assert.throws(() => renderPlayerPublication({ ...common, conversation: duplicate }), (error) => error.code === "duplicate_publication"); const missingParticipant = participants(instance); delete missingParticipant.npc1; const claimInstance = await committed([{ type: "result_claim", targetId: "npc1", result: "werewolf", sourceSpan: { start: 0, end: 5 } }]); assert.throws(() => renderPlayerPublication({ gameSessionId: claimInstance.state.gameSessionId, conversation: claimInstance.state.conversation, legacyPlayerLog: claimInstance.state.playerLog, publicationId: claimInstance.state.conversation.publications[0].publicationId, publicParticipantsById: missingParticipant }), (error) => error.code === "missing_public_participant_projection"); assert.throws(() => renderPlayerPublication({ ...common, activeGameSessionId: "game-new", conversation: instance.state.conversation }), (error) => error.code === "mismatched_session");
});

