  const instance = consumerGame([{ type: "non_game_statement", sourceSpan: { start: 0, end: 5 } }], true), first = await instance.dispatchPlayerAction({ type: "ask_npc", targetId: "npc1", input: "hello", logCursor: 1 }); await deliverLivePlayerEntries({ game: instance, entries: first.livePlayerDisplayEntries, consumerId: "test", sinkType: "browser", writeStructured: async () => {}, writeLegacy: async () => {} }); const firstPublication = first.structuredPlayerEntries[0].publicationId; instance.state.phase = "day_discussion"; instance.interpreterProvider = interpreterFor([{ type: "non_game_statement", sourceSpan: { start: 0, end: 5 } }]); const second = await instance.dispatchPlayerAction({ type: "ask_npc", targetId: "npc1", input: "hello", logCursor: first.nextLogCursor }), secondPublication = second.structuredPlayerEntries.find((entry) => entry.publicationId !== firstPublication); assert.ok(secondPublication); assert.equal(second.playerFacingEntries.filter((entry) => entry.structured).length, 1); assert.equal(second.playerFacingEntries.some((entry) => entry.message === "Aoi: NPC response"), true); assert.notEqual(instance.getPlayerLegacyDisplayCompatibilityRecord({ publicationId: firstPublication }).legacyLogAppendOrder, instance.getPlayerLegacyDisplayCompatibilityRecord({ publicationId: secondPublication.publicationId }).legacyLogAppendOrder);
